#include <iostream>
class Account {
public:
  Account(int starting) : balance_(starting) {}
  void deposit(int amount) { if (amount > 0) balance_ += amount; }
  int balance() const { return balance_; }
private:
  int balance_;
};
int main() {
  Account account(20);
  account.deposit(5);
  std::cout << account.balance() << "\n";
}

